class Solution:
    def longestSquareStreak(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        num_set = set(nums)
        dp = {}
        max_streak = -1

        for num in num_set:
            if num in dp:
                continue

            streak = 1
            current = num

            while current * current in num_set:
                current = current * current
                streak += 1

            dp[num] = streak

            if streak >= 2:
                max_streak = max(max_streak, streak)

        return max_streak
